var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`MILLIA_COLLABO_NULL_NULL`,text:{KOREA:`이 서류가 당신이 줄 수 있는 최대한의 호평이겠지.`,JPN:`この書類が貴方が私にくれる最大限の評価なんでしょうね。`,ENG:`This document must be your ultimate form of complimenting me.`,TWN:`This document must be your ultimate form of complimenting me.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MILLIA_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`MILLIA_COLLABO_NULL_NULL`,text:{KOREA:`자신감이 대단하네.`,JPN:`大した自信ね。`,ENG:`Such confidence.`,TWN:`Such confidence.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MILLIA_COLLABO_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`MILLIA_COLLABO_NULL_NULL`,text:{KOREA:`겉으로는 작은 회사의 간판만 내걸어 두고 이런 제안을 하다니…`,JPN:`見た目は小さな会社のくせにこんな提案をするなんて……`,ENG:`To make such an offer, while all you have on the outside is a small company...`,TWN:`To make such an offer, while all you have on the outside is a small company...`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MILLIA_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`MILLIA_COLLABO_NULL_NULL`,text:{KOREA:`아니면, 마지막까지 비밀을 파헤쳐 보라는 테스트인가?`,JPN:`でなければ、最後まで秘密を暴いてみろというテストなのかしら？`,ENG:`Or is this a test to see if I can uncover the secrets you keep?`,TWN:`Or is this a test to see if I can uncover the secrets you keep?`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MILLIA_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`MILLIA_COLLABO_NULL_NULL`,text:{KOREA:`전자라면 경솔하다고 하겠지만, 후자가 분명하니 교활하다고 해 주겠어.`,JPN:`前者なら軽率だと言わざるを得ないけど、後者だろうから狡猾と言ってあげるわ。`,ENG:`Should it be the prior, I would say you're rude. Alas, I'm confident it's the latter. Thus, you're cunning.`,TWN:`Should it be the prior, I would say you're rude. Alas, I'm confident it's the latter. Thus, you're cunning.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MILLIA_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`MILLIA_COLLABO_NULL_NULL`,text:{KOREA:`……`,JPN:`……`,ENG:`...`,TWN:`...`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MILLIA_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`MILLIA_COLLABO_NULL_NULL`,text:{KOREA:`그래, 내 기준으로는 아슬아슬하게 합격이야.`,JPN:`そうね、私の基準ではぎりぎり合格よ。`,ENG:`Yes, this is a very close pass for my standards.`,TWN:`Yes, this is a very close pass for my standards.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MILLIA_COLLABO_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`MILLIA_COLLABO_NULL_NULL`,text:{KOREA:`지금은 손을 잡더라도, 앞으로는 더 진지하게 해 주길 바래.`,JPN:`今は手を組んだとしても、この先もっと誠実に対応してくれることを願うわ。`,ENG:`We might have formed an alliance for now, but please put more consideration into this later.`,TWN:`We might have formed an alliance for now, but please put more consideration into this later.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MILLIA_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};